function solve(n) {
    // Helper function to check if a number is a palindrome
    function isPalindrome(num) {
        const str = num.toString();
        return str === str.split('').reverse().join('');
    }

    // Helper function to check if a number meets the special number condition
    function isSpecial(num) {
        const str = num.toString();
        const count = {};
        for (const ch of str) {
            const digit = parseInt(ch);
            if (count[digit] === digit) {
                return false;
            }
            count[digit] = (count[digit] || 0) + 1;
        }
        return true;
    }

    // Start checking from n + 1
    let current = n + 1;
    while (true) {
        if (isPalindrome(current) && isSpecial(current)) {
            return current;
        }
        current++;
    }
}

